using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    // --- CreateOrder: validation ---

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));
        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    // --- CreateOrder: happy path ---

    [TestMethod]
    public void CreateOrder_SingleItem_ReturnsOrderWithCorrectTotal()
    {
        var items = CreateItems(("Widget", 25.50m, 2));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(51.00m, order.Total);
        Assert.IsNotNull(order.Id);
        Assert.ContainsSingle(order.Items);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_ReturnsSumOfAllItems()
    {
        var items = CreateItems(("A", 10m, 2), ("B", 5m, 3), ("C", 100m, 1));

        var order = _service.CreateOrder("cust-1", items);

        // 10*2 + 5*3 + 100*1 = 20 + 15 + 100 = 135
        Assert.AreEqual(135m, order.Total);
        Assert.HasCount(3, order.Items);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;
        var order = _service.CreateOrder("cust-1", CreateItems(("X", 1m, 1)));
        var after = DateTime.UtcNow;

        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt} should be between {before} and {after}.");
    }

    [TestMethod]
    public void CreateOrder_GeneratesUniqueIds()
    {
        var items = CreateItems(("X", 1m, 1));

        var order1 = _service.CreateOrder("cust-1", items);
        var order2 = _service.CreateOrder("cust-1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsMatchingOrder()
    {
        var created = _service.CreateOrder("cust-1", CreateItems(("W", 10m, 1)));

        var retrieved = _service.GetOrder(created.Id);

        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
        Assert.AreEqual(created.CustomerId, retrieved.CustomerId);
        Assert.AreEqual(created.Total, retrieved.Total);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // --- GetOrdersByCustomer ---

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyMatchingOrders()
    {
        _service.CreateOrder("alice", CreateItems(("A", 1m, 1)));
        _service.CreateOrder("bob", CreateItems(("B", 2m, 1)));
        _service.CreateOrder("alice", CreateItems(("C", 3m, 1)));

        var aliceOrders = _service.GetOrdersByCustomer("alice");

        Assert.HasCount(2, aliceOrders);
        Assert.IsTrue(aliceOrders.All(o => o.CustomerId == "alice"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_UnknownCustomer_ReturnsEmptyList()
    {
        _service.CreateOrder("alice", CreateItems(("A", 1m, 1)));

        var result = _service.GetOrdersByCustomer("unknown");

        Assert.IsEmpty(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsReadOnlyList()
    {
        _service.CreateOrder("cust-1", CreateItems(("X", 5m, 1)));

        var result = _service.GetOrdersByCustomer("cust-1");

        Assert.IsInstanceOfType<IReadOnlyList<Order>>(result);
    }
}

